# 条件语句示例
age = 18

if age >= 18:
    print("你是成年人")
elif age >= 13:
    print("你是青少年")
else:
    print("你是儿童")

# 逻辑运算符
x = 10
y = 5

if x > 5 and y < 10:
    print("两个条件都满足")

if x > 5 or y > 10:
    print("至少有一个条件满足")

# for循环示例
for i in range(5):
    print(i)  # 输出: 0, 1, 2, 3, 4

# while循环示例
count = 0
while count < 5:
    print(count)
    count += 1

# break和continue
for i in range(10):
    if i == 5:
        break  # 终止循环
    if i % 2 == 0:
        continue  # 跳过当前迭代
    print(i)

# 基本异常处理
try:
    num = int(input("请输入一个数字: "))
    result = 10 / num
    print("结果:", result)
except ValueError:
    print("错误: 请输入有效的数字")
except ZeroDivisionError:
    print("错误: 除数不能为零")
except Exception as e:
    print("发生了错误:", str(e))
finally:
    print("程序执行完毕")

import random

def guess_number():
    """猜数字游戏"""
    number = random.randint(1, 100)
    attempts = 0

    print("欢迎来到猜数字游戏！")
    print("我已经想好了一个1到100之间的数字，你有10次机会猜它。")

    while attempts < 10:
        try:
            guess = int(input("请输入你的猜测: "))
            attempts += 1

            if guess < number:
                print("太小了！")
            elif guess > number:
                print("太大了！")
            else:
                print(f"恭喜你，猜对了！你用了{attempts}次机会。")
                return
        except ValueError:
            print("请输入有效的数字！")

    print(f"很遗憾，你没有在10次机会内猜对。正确答案是{number}。")

# 运行游戏
guess_number()
